module RefModule(
    input in,
    output reg out,  // Change the output declaration to reg
    input clk
);reg obf_prev_in;

    always @(posedge clk) begin
        if (in && !obf_prev_in) begin
            out <= 1'b1;
        end else begin
            out <= 1'b0;
        end
        obf_prev_in <= in;
    end

endmodule
